namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private readonly List<Notification> _notifications = new();
    private int _nextId = 1;
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.Add(new(NextId(), "Welcome to the app!", DateTime.UtcNow.AddMinutes(-30)));
        _notifications.Add(new(NextId(), "Your profile was updated.", DateTime.UtcNow.AddMinutes(-15)));
        _notifications.Add(new(NextId(), "New feature: dark mode is available.", DateTime.UtcNow.AddMinutes(-5)));
    }

    /// <summary>Returns all notifications.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return [.. _notifications];
        }
    }

    /// <summary>Returns only notifications newer than the given id.</summary>
    public List<Notification> GetSince(int lastSeenId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > lastSeenId).ToList();
        }
    }

    /// <summary>Simulates an external system pushing new notifications over time.</summary>
    public void SimulateIncoming()
    {
        string[] messages =
        [
            "Server CPU usage spike detected.",
            "Deployment to staging completed.",
            "User JaneDoe signed up.",
            "Backup finished successfully.",
            "New comment on issue #42.",
            "CI pipeline passed.",
            "Disk space warning on node-3.",
        ];

        lock (_lock)
        {
            var msg = messages[Random.Shared.Next(messages.Length)];
            _notifications.Add(new(NextId(), msg, DateTime.UtcNow));
        }
    }

    private int NextId() => _nextId++;
}

@page "/notifications"
@rendermode InteractiveServer
@using NotificationsApp.Services
@inject NotificationService Svc
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span style="background:#0d6efd;color:#fff;border-radius:999px;padding:2px 10px;font-size:0.6em;vertical-align:middle;">
        @_notifications.Count
    </span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul>
        @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
        {
            <li>
                <strong>@n.Timestamp.ToString("HH:mm:ss")</strong> &mdash; @n.Message
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = [];
    private int _lastSeenId;
    private CancellationTokenSource? _cts;

    // Runs during SSR *and* when the component re-initializes interactively.
    // We only load from the service on the very first call (SSR).  The second
    // call (interactive) skips the fetch because _notifications is already
    // populated via persistent component state (see below).
    protected override void OnInitialized()
    {
        if (_notifications.Count == 0)
        {
            _notifications = Svc.GetAll();
            _lastSeenId = _notifications.Count > 0
                ? _notifications.Max(n => n.Id)
                : 0;
        }
    }

    // Called only once the circuit is live (interactive).  Safe to start
    // long-running async work here — this never fires during static SSR.
    protected override Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
        return Task.CompletedTask;
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct).ConfigureAwait(false);

            // Simulate an external system producing a notification.
            Svc.SimulateIncoming();

            var newer = Svc.GetSince(_lastSeenId);
            if (newer.Count > 0)
            {
                _notifications.AddRange(newer);
                _lastSeenId = newer.Max(n => n.Id);

                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

